#include<bits/stdc++.h>
using namespace std;
struct node
{
    int l,r;
    bool operator<(const node&b)const
    {
        return l<b.l;
    }
}a[25010];
int main()
{
    int n,t;
    scanf("%d%d",&n,&t);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&a[i].l,&a[i].r);
    }
    sort(a+1,a+1+n);
    int st=1,ans=0;
    for(int i=1,j=1;i<=n;)
    {
        int r=0;
        while(j<=n&&a[j].l<=st)
        {
            r=max(r,a[j].r);
            j++;
        }
        if(r<st)
        {
            break;
        }
        ans++;
        if(r>=t)
        {
            printf("%d",ans);
            return 0;
        }
        st=r+1;
        i=j;
    }
    printf("-1");
    return 0;
}
